import * as React from "react"

export function useRenderLock(initialLocked = true) {
  const [locked, setLocked] = React.useState(initialLocked)

  const lock = React.useCallback(() => {
    setLocked(true)
  }, [])

  const unlock = React.useCallback(() => {
    setLocked(false)
  }, [])

  return {
    locked,
    lock,
    unlock,
  }
}
